settings.custom_liquid:
{% assign watch_blog = blogs['watch'] %}

<section class="ra-section ra-watch">
  <div class="ra-container">
    <div class="ra-section-header">
      <h1 class="ra-section-header__title">Watch</h1>
      <p class="ra-section-header__text">
        Independent commentary, livestreams, interviews, and conversations that go beyond the headlines.
      </p>
    </div>

    <div class="ra-filters" aria-label="Video categories">
      <button class="ra-filter is-active" data-filter="all" type="button">All</button>
      <button class="ra-filter" data-filter="livestream" type="button">Livestream</button>
      <button class="ra-filter" data-filter="interviews" type="button">Interviews</button>
      <button class="ra-filter" data-filter="commentary" type="button">Commentary</button>
    </div>

    <div class="ra-grid-3">
      {% for article in watch_blog.articles limit: 24 %}
        {% assign category = article.metafields.custom.category.value | default: article.metafields.custom.category | default: 'Commentary' %}
        {% assign category_handle = category | handleize %}
        {% assign youtube_url = article.metafields.custom.youtube_url.value | default: article.metafields.custom.youtube_url %}
        {% assign video_id = '' %}

        {% if youtube_url contains 'youtu.be/' %}
          {% assign video_id = youtube_url | split: 'youtu.be/' | last | split: '?' | first | split: '&' | first %}
        {% elsif youtube_url contains 'watch?v=' %}
          {% assign video_id = youtube_url | split: 'watch?v=' | last | split: '&' | first %}
        {% elsif youtube_url contains '/embed/' %}
          {% assign video_id = youtube_url | split: '/embed/' | last | split: '?' | first | split: '&' | first %}
        {% elsif youtube_url contains '/live/' %}
          {% assign video_id = youtube_url | split: '/live/' | last | split: '?' | first | split: '&' | first %}
        {% elsif youtube_url contains '/shorts/' %}
          {% assign video_id = youtube_url | split: '/shorts/' | last | split: '?' | first | split: '&' | first %}
        {% endif %}

        <article class="ra-video-card" data-category="{{ category_handle }}">
          <a href="{{ article.url }}" class="ra-video-card__link" aria-label="Watch {{ article.title | escape }}">
            <div class="ra-video-card__thumb">
              {% if video_id != blank %}
                <img
                  src="https://img.youtube.com/vi/{{ video_id }}/hqdefault.jpg"
                  alt="{{ article.title | escape }}"
                  loading="lazy"
                >
              {% elsif article.image %}
                <img
                  src="{{ article.image | image_url: width: 900 }}"
                  alt="{{ article.title | escape }}"
                  loading="lazy"
                >
              {% endif %}
            </div>

            <div class="ra-video-card__body">
              <div class="ra-video-card__category">{{ category }}</div>
              <h2 class="ra-video-card__title">{{ article.title }}</h2>
              <div class="ra-video-card__meta">{{ article.published_at | date: "%b %-d, %Y" }}</div>
            </div>
          </a>
        </article>
      {% endfor %}
    </div>

    <p class="ra-empty" hidden>No videos found in this category.</p>
  </div>
</section>

<script>
  document.addEventListener('DOMContentLoaded', function () {
    const filters = document.querySelectorAll('.ra-filter');
    const cards = document.querySelectorAll('.ra-video-card');
    const empty = document.querySelector('.ra-empty');

    filters.forEach(button => {
      button.addEventListener('click', () => {
        const filter = button.dataset.filter;
        let visibleCount = 0;

        filters.forEach(btn => btn.classList.remove('is-active'));
        button.classList.add('is-active');

        cards.forEach(card => {
          const match = filter === 'all' || card.dataset.category === filter;
          card.style.display = match ? '' : 'none';
          if (match) visibleCount++;
        });

        if (empty) {
          empty.hidden = visibleCount !== 0;
        }
      });
    });
  });
</script>
